import React, { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import toast from 'react-hot-toast';
import { Cpu, Terminal, Lock, ShieldCheck } from 'lucide-react';

const LoginPage = () => {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const { login, loading } = useAuth();
  const navigate = useNavigate();

  const handleLogin = async (e) => {
    e.preventDefault();
    if (!email || !password) return toast.error('FIELDS_REQUIRED');

    const toastId = toast.loading('INITIALIZING_SECURE_HANDSHAKE...');
    try {
      // login handles the OAuth2 conversion internally for the FastAPI backend
      await login(email, password);
      toast.success('ACCESS_GRANTED', { id: toastId });
      navigate('/dashboard');
    } catch (error) {
      toast.error('GATE_REJECTION: INVALID_CREDENTIALS', { id: toastId });
    }
  };

  return (
    /* 🎯 THE CENTERING ENGINE:
       min-h-[85vh] and flex items-center justify-center ensure the card 
       is perfectly centered with the padding seen in your mockup. */
    <div className="min-h-[85vh] w-full flex flex-col items-center justify-center px-4 py-8 reveal-data">
      
      {/* 🏛️ The Cyber Card: Small and compact (max-w-md) with frosted glass effect */}
      <div className="w-full max-w-md cyber-card relative overflow-hidden shadow-2xl">
        
        {/* Ambient Emerald Glow matching the theme */}
        <div className="absolute -top-32 -left-32 w-64 h-64 bg-emerald-600/20 blur-[120px]" />

        {/* 📐 Internal Card Padding: creates the professional inner gutter */}
        <div className="relative z-10 p-6 sm:p-8">
          
          {/* Header Section */}
          <div className="text-center mb-8">
            <div className="flex justify-center mb-6 text-emerald-400">
              <Cpu size={42} className="animate-pulse" />
            </div>
            <h1 className="text-3xl font-light tracking-tight text-white mb-2">
              Welcome Back
            </h1>
            <p className="text-white/40 text-[10px] uppercase tracking-[0.25em] font-mono">
              Sign in to access your node // SECURE_GATE_V3
            </p>
          </div>

          <form onSubmit={handleLogin} className="space-y-5">
            {/* Email Field */}
            <div className="space-y-2">
              <label className="flex items-center gap-2 text-[10px] text-emerald-400 font-bold uppercase tracking-widest ml-1">
                <Terminal size={12} /> Email Address
              </label>
              <input
                type="email"
                className="cyber-input"
                placeholder="operator@finify.ai"
                value={email}
                onChange={(e) => setEmail(e.target.value)}
                autoComplete="email"
                required
              />
            </div>

            {/* Password Field */}
            <div className="space-y-2">
              <label className="flex items-center gap-2 text-[10px] text-emerald-400 font-bold uppercase tracking-widest ml-1">
                <Lock size={12} /> Master Key
              </label>
              <input
                type="password"
                className="cyber-input"
                placeholder="••••••••"
                value={password}
                onChange={(e) => setPassword(e.target.value)}
                autoComplete="current-password"
                required
              />
            </div>

            {/* Action Button */}
            <button
              type="submit"
              disabled={loading}
              className={`cyber-btn mt-4 w-full ${loading ? 'opacity-60 cursor-not-allowed' : 'hover:scale-[1.01]'}`}
            >
              {loading ? 'SYNCHRONIZING...' : (
                <span className="flex items-center justify-center gap-2">
                  <ShieldCheck size={16} /> Sign In
                </span>
              )}
            </button>
          </form>

          {/* Footer Navigation */}
          <div className="mt-8 pt-6 border-t border-white/5 text-center">
            <p className="text-[10px] text-white/30 uppercase tracking-[0.25em]">
              Don&apos;t have an account?{' '}
              <Link to="/register" className="text-emerald-400 hover:underline transition-colors">
                Sign Up
              </Link>
            </p>
          </div>
        </div>
      </div>
    </div>
  );
};

export default LoginPage;
